# OnchainKit Provider 初始化

## 基本安装

```bash
npm install @coinbase/onchainkit
```

## 基础配置

```tsx
import { OnchainKitProvider } from '@coinbase/onchainkit';
import { base } from 'wagmi/chains';

function App() {
  return (
    <OnchainKitProvider
      apiKey="YOUR_API_KEY"        // 必填：CDP API Key
      chain={base}                  // 必填：目标链
    >
      {children}
    </OnchainKitProvider>
  );
}
```

## 完整配置选项

```tsx
<OnchainKitProvider
  apiKey="YOUR_API_KEY"
  chain={base}
  config={{
    appearance: {
      name: '你的应用名称',
      logo: 'https://your-logo.png',
      mode: 'auto',              // 'light' | 'dark' | 'auto'
      theme: 'default',          // 'default' | 'cyberpunk' | 'base' | ...
    },
    paymaster: 'YOUR_PAYMASTER_URL',  // 可选：Gas 赞助
  }}
