# ERC-721 transferFrom vs safeTransferFrom

## 核心区别

```solidity
// 普通版本 - 直接转移，不检查接收方
function transferFrom(address from, address to, uint256 tokenId) external;

// 安全版本 - 转移后检查接收方是否能处理NFT
function safeTransferFrom(address from, address to, uint256 tokenId) external;
function safeTransferFrom(address from, address to, uint256 tokenId, bytes calldata data) external;
```

## 关键差异：接收方检查

```
transferFrom:
  EOA地址  ✅ 正常接收
  合约地址 ✅ 转移成功，但NFT可能永久锁死！

safeTransferFrom:
  EOA地址  ✅ 正常接收
  合约地址 ✅ 必须实现 onERC721Received，否则回滚
```

## safeTransferFrom 内部逻辑

```solidity
function safeTransferFrom(address from, address to, uint256 tokenId) public {
    transferFrom(from, to, tokenId); // 先执行普通转移

    // 再检查接收方
    require(_checkOnERC721Received(from, to, tokenId, ""));
}

function _checkOnERC721Received(...) private returns (bool) {
    if (to.code.length == 0) {
        return true; // EOA，直接通过
    }

    // 合约必须返回魔法值
    bytes4 retval = IERC721Receiver(to).onERC721Received(
        msg.sender, from, tokenId, data
    );

    return retval == IERC721Receiver.onERC721Received.selector;
    // 必须返回 0x150b7a02
}
```

## 接收合约必须实现

```solidity
contract NFTReceiver is IERC721Receiver {
    function onERC721Received(
        address operator,
        address from,
        uint256 tokenId,
        bytes calldata data
    ) external override returns (bytes4) {
        // 自定义逻辑...

        // 必须返回这个魔法值，否则转移回滚
        return IERC721Receiver.onERC721Received.selector;
        // 等价于 return 0x150b7a02;
    }
}
```

